fix_patch:
diff --git a/metrics/metrics.go b/metrics/metrics.go
index 329981202..9ba1512ad 100644
--- a/metrics/metrics.go
+++ b/metrics/metrics.go
@@ -18,6 +18,7 @@ import (
 	"fmt"
 	"io"
 	"math"
+	"reflect"
 	"sort"
 	"strconv"
 	"strings"
@@ -59,6 +60,10 @@ func (d *diff) add(v interface{}) *diff {
 		return d
 	}

+	if d.count == 0 {
+		d.baseline = v
+	}
+
 	d.simSum += howSimilar(v, d.baseline)
 	d.count++

@@ -202,6 +207,17 @@ func howSimilar(a, b interface{}) int {
 	as, ok1 := a.(string)
 	bs, ok2 := b.(string)

+	if !ok1 {
+		if ra := reflect.ValueOf(a); ra.IsValid() && ra.Kind() == reflect.String {
+			as, ok1 = ra.String(), true
+		}
+	}
+	if !ok2 {
+		if rb := reflect.ValueOf(b); rb.IsValid() && rb.Kind() == reflect.String {
+			bs, ok2 = rb.String(), true
+		}
+	}
+
 	if ok1 && ok2 {
 		return howSimilarStrings(as, bs)
 	}
